insert into public.quiz_questions (id, question, options, correct_index, theme) values
  (1, 'Quale paese ha ospitato e vinto la prima edizione assoluta dei Mondiali nel 1930?', '["Argentina","Brasile","Uruguay","Italia"]'::jsonb, 2, 'mondiali_2026'),
